};

const express = require('express');
const router = express.Router({ mergeParams: true });
const { createTask, updateTaskStatus, getTasksByStatus } = require('./service');

// Create a new task
router.post('/', async (req, res) => {
  const task = await createTask({ id: randomUUID(), status: 'todo', ...req.body });
  res.status(201).send({ task });
});

// Update task status
router.patch('/:taskId', async (req, res) => {
  const { taskId } = req.params;
  if (!['todo', 'done'].includes(req.body.status)) return sendError(res, 400, 'BadRequest', 'Invalid status');
  const task = await updateTaskStatus(taskId, req.body.status);
  res.send({ task });
});

// Get tasks by status
router.get('/', async (req, res) => {
  const { status } = req.query;
  if (!status || !['todo', 'done'].includes(status)) return sendError(res, 400, 'BadRequest', 'Invalid status filter');
  const tasks = await getTasksByStatus(status);
  res.send({ tasks });
});

module.exports = router;

const db = { tasks: [] }; // In-memory database for simplicity

exports.createTask = function(task) {
  db.tasks.push(task);
  return task;
};

exports.updateTaskStatus = function(taskId, newStatus) {
  const taskIndex = db.tasks.findIndex(task => task.id === taskId);
  if (taskIndex === -1) return null;
  db.tasks[taskIndex].status = newStatus;
  return db.tasks[taskIndex];
};

exports.getTasksByStatus = function(status) {
  return db.tasks.filter(task => task.status === status);
};

